import plistlib, os, glob

# Rename UFO directories and fix family/style names
renames = {
    "Cambay Devanagari-Regular.ufo": "Cambay-Regular.ufo",
    "Cambay Devanagari-Oblique.ufo": "Cambay-Italic.ufo",
    "Cambay Devanagari-Bold.ufo": "Cambay-Bold.ufo",
    "Cambay Devanagari-Bold Oblique.ufo": "Cambay-BoldItalic.ufo",
}

for old_name, new_name in renames.items():
    for d in glob.glob("Sources/*/"):
        old_path = os.path.join(d, old_name)
        new_path = os.path.join(d, new_name)
        if os.path.exists(old_path):
            os.rename(old_path, new_path)
            print(f"Renamed: {old_path} -> {new_path}")

            fontinfo = os.path.join(new_path, "fontinfo.plist")
            if os.path.exists(fontinfo):
                with open(fontinfo, "rb") as f:
                    info = plistlib.load(f)
                for key in ["familyName", "openTypeNamePreferredFamilyName"]:
                    if key in info and "Devanagari" in str(info[key]):
                        info[key] = info[key].replace(" Devanagari", "")
                # Fix style names
                if "styleName" in info:
                    info["styleName"] = info["styleName"].replace("Oblique", "Italic")
                if "openTypeNamePreferredSubfamilyName" in info:
                    info["openTypeNamePreferredSubfamilyName"] = info["openTypeNamePreferredSubfamilyName"].replace("Oblique", "Italic")
                if "styleMapStyleName" in info:
                    info["styleMapStyleName"] = info["styleMapStyleName"].replace("oblique", "italic")
                with open(fontinfo, "wb") as f:
                    plistlib.dump(info, f)
