import os, glob, re, json

# Fix source UFOs (.glif files)
for root, dirs, files in os.walk('source'):
    if root.endswith('/glyphs'):
        for f in files:
            if 'SngStory' in f and f.endswith('.glif'):
                path = os.path.join(root, f)
                data = open(path).read()
                if '<unicode hex=' in data:
                    new = re.sub(r'  <unicode hex="[0-9A-Fa-f]+"/>\n', '', data)
                    if new != data:
                        open(path, 'w').write(new)
                        print(f'Fixed source UFO: {path}')

# Fix JSON instance UFOs - these are single JSON files with nested structure
for json_ufo in glob.glob('source/instance_ufos/*.ufo.json'):
    with open(json_ufo) as f:
        data = f.read()

    # The JSON UFO stores glyphs with their unicodes
    # We need to find SngStory glyphs and remove their unicode values
    obj = json.loads(data)
    modified = False

    # JSON UFO structure has "glyphs" at top level
    if 'glyphs' in obj:
        for glyph_name in list(obj['glyphs'].keys()):
            if 'SngStory' in glyph_name:
                glyph = obj['glyphs'][glyph_name]
                if isinstance(glyph, dict) and 'unicodes' in glyph and glyph['unicodes']:
                    glyph['unicodes'] = []
                    modified = True

    # Also check layered structure
    if 'layers' in obj:
        for layer in obj['layers']:
            if isinstance(layer, dict) and 'glyphs' in layer:
                glyphs = layer['glyphs']
                if isinstance(glyphs, dict):
                    for glyph_name in list(glyphs.keys()):
                        if 'SngStory' in glyph_name:
                            glyph = glyphs[glyph_name]
                            if isinstance(glyph, dict) and 'unicodes' in glyph:
                                glyph['unicodes'] = []
                                modified = True

    if modified:
        with open(json_ufo, 'w') as f:
            json.dump(obj, f)
        print(f'Fixed JSON UFO: {json_ufo}')
    else:
        # If we couldn't find glyphs, just do string replacement
        if 'SngStory' in data and '"A7BB"' in data.upper():
            print(f'WARNING: Could not fix {json_ufo} programmatically')
